import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { SearchIcon, FilterIcon, BookOpenIcon } from 'lucide-react';
import { StarRating } from '../components/StarRating';
import { Modal } from '../components/Modal';

const SUBJECTS = ['Python', 'Calculus', 'Physics', 'Chemistry', 'English', 'Statistics', 'Economics', 'Biology'];
const AVAILABILITY = ['Available Now', 'This Week', 'Any Time'];

const VOLUNTEERS = [
  { id: 1, name: 'Sarah Chen', subjects: ['Python', 'Statistics', 'Biology'], score: 92, rating: 4.8, color: 'bg-blue-500' },
  { id: 2, name: 'Marcus Johnson', subjects: ['Calculus', 'Physics'], score: 87, rating: 4.5, color: 'bg-emerald-500' },
  { id: 3, name: 'Elena Rodriguez', subjects: ['Chemistry', 'Biology'], score: 95, rating: 4.9, color: 'bg-purple-500' },
  { id: 4, name: 'David Kim', subjects: ['Economics', 'Statistics'], score: 78, rating: 4.2, color: 'bg-amber-500' },
  { id: 5, name: 'Aisha Patel', subjects: ['English', 'Python'], score: 88, rating: 4.6, color: 'bg-pink-500' },
  { id: 6, name: 'James Wilson', subjects: ['Physics', 'Calculus'], score: 82, rating: 4.4, color: 'bg-indigo-500' },
  { id: 7, name: 'Chloe Smith', subjects: ['English', 'Biology'], score: 98, rating: 5.0, color: 'bg-rose-500' },
  { id: 8, name: 'Daniel Lee', subjects: ['Python', 'Economics', 'Calculus'], score: 91, rating: 4.7, color: 'bg-cyan-500' }
];

export function CourseDiscovery() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedSubjects, setSelectedSubjects] = useState([]);
  const [selectedAvailability, setSelectedAvailability] = useState('Any Time');
  const [isMobileFiltersOpen, setIsMobileFiltersOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedVolunteer, setSelectedVolunteer] = useState(null);
  const [requestForm, setRequestForm] = useState({
    subject: '',
    date: '',
    time: '9:00 AM',
    message: ''
  });

  const toggleSubject = (subject) => {
    setSelectedSubjects((prev) => (prev.includes(subject) ? prev.filter((s) => s !== subject) : [...prev, subject]));
  };

  const filteredVolunteers = VOLUNTEERS.filter((v) => {
    const matchesSearch =
      v.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      v.subjects.some((s) => s.toLowerCase().includes(searchQuery.toLowerCase()));
    const matchesSubjects = selectedSubjects.length === 0 || v.subjects.some((s) => selectedSubjects.includes(s));

    return matchesSearch && matchesSubjects;
  });

  const containerVariants = {
    hidden: { opacity: 0 },
    show: { opacity: 1, transition: { staggerChildren: 0.05 } }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    show: { opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 24 } }
  };

  const handleOpenModal = (volunteer) => {
    setSelectedVolunteer(volunteer);
    setRequestForm({
      subject: volunteer.subjects[0] || '',
      date: '',
      time: '9:00 AM',
      message: ''
    });
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedVolunteer(null);
  };

  const handleSubmitRequest = (e) => {
    e.preventDefault();
    console.log('Request submitted:', requestForm);
    handleCloseModal();
    alert('Request submitted successfully!');
  };

  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const minDate = tomorrow.toISOString().split('T')[0];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-gray-900">Find Your Tutor</h1>
          <p className="text-gray-500 mt-1">Connect with peer volunteers for academic support.</p>
        </div>
        <button
          className="md:hidden flex items-center justify-center space-x-2 w-full py-2.5 bg-white border border-gray-200 rounded-lg text-gray-700 font-medium shadow-sm"
          onClick={() => setIsMobileFiltersOpen(!isMobileFiltersOpen)}
        >
          <FilterIcon className="w-4 h-4" />
          <span>{isMobileFiltersOpen ? 'Hide Filters' : 'Show Filters'}</span>
        </button>
      </div>

      <div className="flex flex-col md:flex-row gap-8">
        <div className={`w-full md:w-64 flex-shrink-0 ${isMobileFiltersOpen ? 'block' : 'hidden md:block'}`}>
          <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm sticky top-6">
            <div className="relative mb-6">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <SearchIcon className="h-4 w-4 text-gray-400" />
              </div>
              <input
                type="text"
                className="block w-full pl-10 pr-3 py-2 border border-gray-200 rounded-md leading-5 bg-gray-50 placeholder-gray-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm transition-colors"
                placeholder="Search subjects or names..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>

            <div className="mb-6">
              <h3 className="text-sm font-semibold text-gray-900 uppercase tracking-wider mb-3">Subjects</h3>
              <div className="space-y-2.5">
                {SUBJECTS.map((subject) => (
                  <label key={subject} className="flex items-center group cursor-pointer">
                    <input
                      type="checkbox"
                      className="h-4 w-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500 cursor-pointer"
                      checked={selectedSubjects.includes(subject)}
                      onChange={() => toggleSubject(subject)}
                    />
                    <span className="ml-3 text-sm text-gray-600 group-hover:text-gray-900 transition-colors">{subject}</span>
                  </label>
                ))}
              </div>
            </div>

            <div>
              <h3 className="text-sm font-semibold text-gray-900 uppercase tracking-wider mb-3">Availability</h3>
              <div className="space-y-2.5">
                {AVAILABILITY.map((option) => (
                  <label key={option} className="flex items-center group cursor-pointer">
                    <input
                      type="radio"
                      name="availability"
                      className="h-4 w-4 text-indigo-600 border-gray-300 focus:ring-indigo-500 cursor-pointer"
                      checked={selectedAvailability === option}
                      onChange={() => setSelectedAvailability(option)}
                    />
                    <span className="ml-3 text-sm text-gray-600 group-hover:text-gray-900 transition-colors">{option}</span>
                  </label>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1">
          {filteredVolunteers.length === 0 ? (
            <div className="text-center py-16 bg-white rounded-xl border border-gray-200 border-dashed">
              <BookOpenIcon className="mx-auto h-12 w-12 text-gray-300" />
              <h3 className="mt-4 text-lg font-medium text-gray-900">No tutors found</h3>
              <p className="mt-1 text-gray-500">Try adjusting your filters or search query.</p>
              <button
                onClick={() => {
                  setSearchQuery('');
                  setSelectedSubjects([]);
                }}
                className="mt-4 text-indigo-600 font-medium hover:text-indigo-500"
              >
                Clear all filters
              </button>
            </div>
          ) : (
            <motion.div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6" variants={containerVariants} initial="hidden" animate="show">
              {filteredVolunteers.map((volunteer) => (
                <motion.div
                  key={volunteer.id}
                  variants={itemVariants}
                  whileHover={{ y: -4, transition: { duration: 0.2 } }}
                  className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col hover:shadow-md transition-shadow"
                >
                  <div className="p-5 flex-1">
                    <div className="flex items-start justify-between mb-4">
                      <div className="flex items-center space-x-3">
                        <div className={`w-12 h-12 rounded-full ${volunteer.color} flex items-center justify-center text-white font-bold text-lg shadow-inner`}>
                          {volunteer.name
                            .split(' ')
                            .map((n) => n[0])
                            .join('')}
                        </div>
                        <div>
                          <h3 className="text-lg font-bold text-gray-900 leading-tight">{volunteer.name}</h3>
                          <StarRating rating={volunteer.rating} />
                        </div>
                      </div>

                      <div className="flex flex-col items-center justify-center relative w-12 h-12">
                        <svg className="w-12 h-12 transform -rotate-90" viewBox="0 0 36 36">
                          <path
                            className="text-gray-100"
                            strokeWidth="3"
                            stroke="currentColor"
                            fill="none"
                            d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                          />
                          <path
                            className="text-indigo-600"
                            strokeWidth="3"
                            strokeDasharray={`${volunteer.score}, 100`}
                            strokeLinecap="round"
                            stroke="currentColor"
                            fill="none"
                            d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
                          />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center flex-col">
                          <span className="text-[10px] font-bold text-gray-700 leading-none">{volunteer.score}</span>
                        </div>
                      </div>
                    </div>

                    <div className="space-y-3">
                      <p className="text-xs text-gray-500 font-medium uppercase tracking-wider">Subjects</p>
                      <div className="flex flex-wrap gap-2">
                        {volunteer.subjects.map((subject) => (
                          <span key={subject} className="px-2.5 py-1 bg-indigo-50 text-indigo-700 text-xs font-medium rounded-md border border-indigo-100">
                            {subject}
                          </span>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="p-4 border-t border-gray-100 bg-gray-50/50 mt-auto">
                    <motion.button
                      whileTap={{ scale: 0.98 }}
                      onClick={() => handleOpenModal(volunteer)}
                      className="w-full py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-lg shadow-sm transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
                    >
                      Request Support
                    </motion.button>
                  </div>
                </motion.div>
              ))}
            </motion.div>
          )}
        </div>
      </div>

      <Modal isOpen={isModalOpen} onClose={handleCloseModal} title="Study Support Request">
        {selectedVolunteer && (
          <form onSubmit={handleSubmitRequest} className="space-y-5">
            <div>
              <p className="text-sm text-gray-600 mb-4">
                Requesting a session with <span className="font-semibold text-gray-900">{selectedVolunteer.name}</span>.
              </p>
            </div>

            <div>
              <label htmlFor="subject" className="block text-sm font-medium text-gray-700 mb-1">
                Subject
              </label>
              <select
                id="subject"
                value={requestForm.subject}
                onChange={(e) => setRequestForm({ ...requestForm, subject: e.target.value })}
                className="block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md border"
                required
              >
                {selectedVolunteer.subjects.map((subject) => (
                  <option key={subject} value={subject}>
                    {subject}
                  </option>
                ))}
              </select>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label htmlFor="date" className="block text-sm font-medium text-gray-700 mb-1">
                  Date
                </label>
                <input
                  type="date"
                  id="date"
                  min={minDate}
                  value={requestForm.date}
                  onChange={(e) => setRequestForm({ ...requestForm, date: e.target.value })}
                  className="block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                  required
                />
              </div>
              <div>
                <label htmlFor="time" className="block text-sm font-medium text-gray-700 mb-1">
                  Time Slot
                </label>
                <select
                  id="time"
                  value={requestForm.time}
                  onChange={(e) => setRequestForm({ ...requestForm, time: e.target.value })}
                  className="block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md border"
                  required
                >
                  {['9:00 AM', '10:00 AM', '11:00 AM', '1:00 PM', '2:00 PM', '3:00 PM', '4:00 PM', '5:00 PM'].map((time) => (
                    <option key={time} value={time}>
                      {time}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            <div>
              <label htmlFor="message" className="block text-sm font-medium text-gray-700 mb-1">
                Message to Volunteer
              </label>
              <textarea
                id="message"
                rows={4}
                value={requestForm.message}
                onChange={(e) => setRequestForm({ ...requestForm, message: e.target.value })}
                placeholder="Specific topics I need help with..."
                className="block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm resize-none"
                required
              />
            </div>

            <div className="pt-2 flex flex-col sm:flex-row-reverse gap-3">
              <motion.button
                whileTap={{ scale: 0.98 }}
                type="submit"
                className="w-full sm:w-auto inline-flex justify-center items-center px-6 py-2.5 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
              >
                Submit Request
              </motion.button>
              <button
                type="button"
                onClick={handleCloseModal}
                className="w-full sm:w-auto inline-flex justify-center items-center px-6 py-2.5 border border-gray-300 text-sm font-medium rounded-md shadow-sm text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
              >
                Cancel
              </button>
            </div>
          </form>
        )}
      </Modal>
    </div>
  );
}
